import{c as a,Q as t,j as i,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"Thin Harness, Fat Skills — Steve Yegge's Framework","description":"","frontmatter":{"url":"https://moonsat.medium.com/thin-harness-fat-skills-a3dd6d2fe2af","title":"Thin Harness, Fat Skills — Steve Yegge's Framework","author":"Moonsat","date":"2026-04-13T00:00:00.000Z","status":"SUCCESS"},"headers":[],"relativePath":"research/ai-articles/42-medium-moonsat-thin-harness.md","filePath":"research/ai-articles/42-medium-moonsat-thin-harness.md","lastUpdated":1779894392000}`),s={name:"research/ai-articles/42-medium-moonsat-thin-harness.md"};function n(o,e,l,h,c,d){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="thin-harness-fat-skills" tabindex="-1">Thin Harness, Fat Skills <a class="header-anchor" href="#thin-harness-fat-skills" aria-label="Permalink to &quot;Thin Harness, Fat Skills&quot;">​</a></h1><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>The author argues that dramatic productivity gains in AI coding (described as &quot;10x to 100x&quot; improvement) stem not from model intelligence but from system architecture. The key principle is &quot;thin harness, fat skills&quot;—minimizing the wrapper around AI while maximizing structured procedural knowledge.</p><h2 id="five-foundational-concepts" tabindex="-1">Five Foundational Concepts <a class="header-anchor" href="#five-foundational-concepts" aria-label="Permalink to &quot;Five Foundational Concepts&quot;">​</a></h2><h3 id="skill-files" tabindex="-1">Skill Files <a class="header-anchor" href="#skill-files" aria-label="Permalink to &quot;Skill Files&quot;">​</a></h3><p>Reusable markdown documents encoding processes rather than prescribing actions. They function like methods with parameters, applying the same procedure across different contexts. The same investigation skill produces medical analysis or forensic research depending on the dataset and query provided.</p><h3 id="the-harness" tabindex="-1">The Harness <a class="header-anchor" href="#the-harness" aria-label="Permalink to &quot;The Harness&quot;">​</a></h3><p>A minimal program (approximately 200 lines) that loops through model execution, manages file I/O, handles context, and enforces safety boundaries. The anti-pattern involves bloated tool definitions consuming excessive tokens and introducing latency through MCP round-trips.</p><h3 id="resolvers" tabindex="-1">Resolvers <a class="header-anchor" href="#resolvers" aria-label="Permalink to &quot;Resolvers&quot;">​</a></h3><p>Context routing systems that load relevant documents based on task type. Rather than maintaining enormous reference files, resolvers dynamically surface appropriate guidance. The author reduced a 20,000-line knowledge document to 200 lines of pointers.</p><h3 id="latent-vs-deterministic-work" tabindex="-1">Latent vs. Deterministic Work <a class="header-anchor" href="#latent-vs-deterministic-work" aria-label="Permalink to &quot;Latent vs. Deterministic Work&quot;">​</a></h3><p>Intelligence (reading, judgment, synthesis) belongs in latent space where models excel. Optimization problems, arithmetic, and SQL queries belong in deterministic layers for reliability. Misalignment causes hallucinations and failures.</p><h3 id="diarization" tabindex="-1">Diarization <a class="header-anchor" href="#diarization" aria-label="Permalink to &quot;Diarization&quot;">​</a></h3><p>Synthesizing structured profiles from multiple documents—the gap between what founders claim and what they&#39;re building, extracted through holistic reading rather than database queries or RAG systems.</p><h2 id="three-layer-architecture" tabindex="-1">Three-Layer Architecture <a class="header-anchor" href="#three-layer-architecture" aria-label="Permalink to &quot;Three-Layer Architecture&quot;">​</a></h2><p>The system stacks as:</p><ul><li><strong>Top:</strong> Fat skills encoding domain judgment</li><li><strong>Middle:</strong> Thin CLI harness for orchestration</li><li><strong>Bottom:</strong> Deterministic application layer</li></ul><p>This directional principle ensures model improvements automatically elevate all skills while maintaining reliability.</p><h2 id="real-world-example-startup-school-matching" tabindex="-1">Real-World Example: Startup School Matching <a class="header-anchor" href="#real-world-example-startup-school-matching" aria-label="Permalink to &quot;Real-World Example: Startup School Matching&quot;">​</a></h2><p>The article demonstrates the framework through a system managing 6,000 founder applications:</p><ul><li><p><strong>Enrichment phase:</strong> Skills aggregate GitHub commits, advisor transcripts, and applications to identify patterns humans miss—distinguishing founders claiming similar domains but solving different problems.</p></li><li><p><strong>Matching strategies:</strong> The same skill invoked three ways produces different clustering logic, each incorporating human judgment about sector relationships and serendipity.</p></li><li><p><strong>Learning loop:</strong> Post-event surveys identify marginal experiences, which get codified into updated matching rules within skill files, improving future iterations without code rewrites.</p></li></ul><h2 id="key-insight-on-permanence" tabindex="-1">Key Insight on Permanence <a class="header-anchor" href="#key-insight-on-permanence" aria-label="Permalink to &quot;Key Insight on Permanence&quot;">​</a></h2><p>Skills represent permanent system upgrades that compound over time. Once codified, they:</p><ul><li>Never degrade</li><li>Improve automatically with new model versions</li><li>Run on schedules without human intervention</li><li>Scale from initial manual instances to automated processes</li></ul><p>The author emphasizes the discipline of refusing one-off work: manually perform a task 3-10 times, approve the pattern, then codify it into a skill.</p><hr><p><strong>Core Message:</strong> Superhuman AI productivity emerges from rigorous architectural choices about what stays thin (the harness) and what stays fat (reusable procedural knowledge), not from raw model capability.</p>',27)])])}const p=a(s,[["render",n]]);export{u as __pageData,p as default};
